[CmdletBinding()]param([Parameter(Mandatory)][string]$ProjectRoot)
$ErrorActionPreference='Stop';$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$studio=Join-Path $project '.studio';if(-not(Test-Path $studio)){throw "Missing project-local state directory: $studio"}
$required=@('PROJECT_BRIEF.md','CONFIRMED_FACTS.md','ASSUMPTIONS.md','TECH_DECISION.md','APPROVED_CONCEPT.md','COPY.md','DESIGN_SYSTEM.md','IMPLEMENTATION_PLAN.md','ACCEPTANCE_CRITERIA.md');$state=Get-Content -Raw -LiteralPath (Join-Path $studio 'PROJECT_STATE.md') -ErrorAction SilentlyContinue
$database=$state -match '(?im)^\s*-?\s*(?:Persistence|Database) required:\s*yes\b';$backend=$state -match '(?im)^\s*-?\s*(?:Backend|Server|API|Form delivery) required:\s*yes\b';$integration=$state -match '(?im)^\s*-?\s*(?:External integration|Integration) required:\s*yes\b';$auth=$state -match '(?im)^\s*-?\s*Authentication required:\s*yes\b';$security=$database -or $backend -or $integration -or $auth -or ($state -match '(?im)^\s*-?\s*Sensitive data:\s*yes\b')
$refactor=($state -match '(?im)^\s*-?\s*(?:Refactor|Structural remediation) required:\s*yes\b') -or ($state -match '(?im)^\s*-?\s*Change type:\s*.*refactor');$performance=$state -match '(?im)^\s*-?\s*(?:Performance|Measured performance) required:\s*yes\b';$release=($state -match '(?im)^\s*-?\s*(?:Release|Deployment|Production handoff) required:\s*yes\b') -or ($state -match '(?im)production SaaS handoff');$operations=($state -match '(?im)^\s*-?\s*(?:Operations|Persistent runtime) required:\s*yes\b') -or (($database -or $backend) -and ($state -match '(?im)(?:production|handoff)'))
if($backend){$required+=@('BACKEND_SPEC.md','API_CONTRACT.md')};if($database){$required+=@('DATABASE_DECISION.md','DATA_MODEL.md','MIGRATION_PLAN.md','DATA_RETENTION.md')};if($integration){$required+=@('INTEGRATION_SPEC.md','EXTERNAL_SERVICES.md','ENVIRONMENT_CONTRACT.md')};if($security){$required+=@('THREAT_MODEL.md','SECURITY_MODEL.md')};if($refactor){$required+=@('REFACTOR_PLAN.md','BEHAVIOR_INVARIANTS.md','ROLLBACK_PLAN.md')};if($performance){$required+=@('PERFORMANCE_BUDGET.md','PERFORMANCE_PLAN.md')};if($release){$required+=@('RELEASE_PLAN.md','DEPLOYMENT_MATRIX.md','RELEASE_CHECKLIST.md','ROLLBACK_PLAN.md')};if($operations){$required+=@('OPERATIONS_PLAN.md','OBSERVABILITY_PLAN.md','HEALTH_CHECKS.md','INCIDENT_RESPONSE.md','RUNBOOK.md','BACKUP_RECOVERY.md')}
$missing=@($required|Select-Object -Unique|Where-Object{-not(Test-Path -LiteralPath (Join-Path $studio $_))});$contradictions=[Collections.Generic.List[string]]::new();function Text([string]$name){$p=Join-Path $studio $name;if(Test-Path $p){Get-Content -Raw $p}else{''}}
if($database -and (Text 'DATABASE_DECISION.md') -match '(?im)Status:\s*`?not applicable'){$contradictions.Add('Persistence is required but DATABASE_DECISION is not applicable.')};if($refactor){$plan=Text 'REFACTOR_PLAN.md';$invariants=Text 'BEHAVIOR_INVARIANTS.md';if($plan -notmatch '(?i)(affected file|files/ownership|owned file)'){$contradictions.Add('Refactor plan lacks affected files and ownership.')};if($plan -notmatch '(?i)(test|characterization|regression)'){$contradictions.Add('Refactor plan lacks test evidence.')};if($plan -notmatch '(?i)rollback'){$contradictions.Add('Refactor plan lacks rollback.')};if(-not $invariants.Trim()){$contradictions.Add('Refactor source changes require behavior invariants.')};if($plan -match '(?i)public behavior.*(?:add|new|change)' -and $plan -notmatch '(?i)product approval'){$contradictions.Add('Refactor plan hides public feature work without product approval.')}}
if($release -and (Text 'RELEASE_PLAN.md') -match '(?i)production.*complete' -and (Text 'DEPLOYMENT_VERIFICATION.md') -notmatch '(?im)^(?:-\s*)?(?:deployment evidence|evidence|provider|verified URL):\s*\S+'){$contradictions.Add('Production release is complete without deployment evidence.')};if($release -and (Text 'RELEASE_REPORT.md') -match '(?i)release-ready' -and (Text 'reports/SECURITY_REPORT.md') -match '(?i)(critical|severity:\s*critical).*unresolved'){$contradictions.Add('Release-ready status has unresolved critical security findings.')};if($operations -and (Text 'OPERATIONS_PLAN.md') -notmatch '(?i)owner'){$contradictions.Add('Persistent runtime requires operational ownership.')};if($operations -and (Text 'OBSERVABILITY_PLAN.md') -match '(?i)alerting.*(?:working|operational)' -and (Text 'OBSERVABILITY_PLAN.md') -notmatch '(?i)delivery evidence'){$contradictions.Add('Alerting is operational without delivery evidence.')};if($operations -and (Text 'BACKUP_RECOVERY.md') -match '(?i)restore.*(?:verified|tested)' -and (Text 'BACKUP_RECOVERY.md') -notmatch '(?i)restore test evidence'){$contradictions.Add('Backup restore is verified without restore-test evidence.')};if($performance -and (Text 'PERFORMANCE_REPORT.md') -match '(?i)(lighthouse|latency|core web vitals|bundle size|throughput).*measured' -and (Text 'PERFORMANCE_REPORT.md') -notmatch '(?i)(measurement method|evidence source)'){$contradictions.Add('Measured performance claim lacks measurement source.')}
$planPath=Join-Path $studio 'reports/specialist-plan.md';$result=if($missing.Count -eq 0 -and $contradictions.Count -eq 0){'passed'}else{'blocked'};$plan=$null;if($result -eq 'passed'){$plan=& (Join-Path $PSScriptRoot 'Resolve-SpecialistPlan.ps1') -ProjectRoot $project -OutputPath $planPath};$report=@('# Implementation preflight','',('- Result: `'+$result+'`'),('- Project root: `'+$project+'`'),("- Required records: $($required -join ', ')"),("- Missing records: $(if($missing.Count){$missing -join ', '}else{'none'})"),("- Contradictions: $(if($contradictions.Count){$contradictions -join ' | '}else{'none'})"),'- Optional, deferred, and not-applicable records require a reason in their own record.','- Approval evidence: `.studio/APPROVED_CONCEPT.md` must exist.',("- Specialist plan: $(if($plan){'.studio/reports/specialist-plan.md'}else{'not resolved because preflight is blocked'})"),("- Decision and date: $([DateTime]::UtcNow.ToString('o'))")) -join [Environment]::NewLine;Set-Content -LiteralPath (Join-Path $studio 'IMPLEMENTATION_PREFLIGHT.md') -Value $report -Encoding utf8;if($result -ne 'passed'){throw "Implementation preflight blocked. Missing records: $($missing -join ', '). Contradictions: $($contradictions -join ', ')"};Write-Host "Implementation preflight passed. Specialist plan: $planPath"
